import{_ as s,o as n,c as e,a1 as t}from"./chunks/framework.BKJzsOC1.js";const p="/assets/figure-6-bounce-vs-reversal.RhpvH-Zg.png",l="/assets/figure-7-retest-validity.B1b6NUzJ.png",i="/assets/figure-8-six-stock-replay.BBxlNztq.png",m=JSON.parse('{"title":"第八章：反弹、反转与回踩有效性","description":"","frontmatter":{},"headers":[],"relativePath":"trading/intraday-entry/08-bounce-reversal-and-retest-validity.md","filePath":"trading/intraday-entry/08-bounce-reversal-and-retest-validity.md"}'),o={name:"trading/intraday-entry/08-bounce-reversal-and-retest-validity.md"};function c(d,a,r,h,u,b){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="第八章-反弹、反转与回踩有效性" tabindex="-1">第八章：反弹、反转与回踩有效性 <a class="header-anchor" href="#第八章-反弹、反转与回踩有效性" aria-label="Permalink to &quot;第八章：反弹、反转与回踩有效性&quot;">​</a></h1><blockquote><p>价格从需求区上涨，只能证明买盘出现；只有结构完成，才能进入建仓评估。</p></blockquote><p>这一章把前面学过的需求区、VWAP、①②③和收线确认合并起来，解决一个最常见的问题：</p><blockquote><p>价格已经从低位反弹了，我现在能不能做多？</p></blockquote><h2 id="一、反弹不等于反转" tabindex="-1">一、反弹不等于反转 <a class="header-anchor" href="#一、反弹不等于反转" aria-label="Permalink to &quot;一、反弹不等于反转&quot;">​</a></h2><p>价格进入需求区后上涨，只能说明这里出现了买盘反应。它不能自动证明下跌趋势已经结束，也不能替代结构确认。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>反弹：价格从低位离开</span></span>
<span class="line"><span>反转：低点抬高 + 收复关键线/VWAP + 出现③ + 后续延续</span></span></code></pre></div><p><img src="`+p+`" alt="需求区反弹与反转确认的 K 线对比"></p><p><em>图 1：左图完成①②③，属于多头建仓候选；右图只是从需求区反弹，没有有效②和③，最后重新走弱。图中价格为构造示例。</em></p><h3 id="左图-反转确认" tabindex="-1">左图：反转确认 <a class="header-anchor" href="#左图-反转确认" aria-label="Permalink to &quot;左图：反转确认&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>需求区</span></span>
<span class="line"><span>→ ① 初次反弹并收复关键线</span></span>
<span class="line"><span>→ ② 回踩守住</span></span>
<span class="line"><span>→ ③ 突破回踩高点</span></span>
<span class="line"><span>→ 多头建仓候选</span></span></code></pre></div><h3 id="右图-反弹失败" tabindex="-1">右图：反弹失败 <a class="header-anchor" href="#右图-反弹失败" aria-label="Permalink to &quot;右图：反弹失败&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>需求区</span></span>
<span class="line"><span>→ 反弹，但没有收复VWAP</span></span>
<span class="line"><span>→ 没有形成有效②</span></span>
<span class="line"><span>→ 没有③</span></span>
<span class="line"><span>→ 跌回需求区或继续下跌</span></span></code></pre></div><p>因此，不能只因为出现绿色 K 线、Call Prem 上升，或者指标出现 <code>Pre Buy</code>，就把反弹当成反转。期权资金流只能辅助确认，不能推翻价格结构。</p><h2 id="二、2回踩到底算不算守住" tabindex="-1">二、②回踩到底算不算守住 <a class="header-anchor" href="#二、2回踩到底算不算守住" aria-label="Permalink to &quot;二、②回踩到底算不算守住&quot;">​</a></h2><p>回踩不是“价格碰到一条线”这么简单。需要同时观察：</p><ol><li>回踩 K 线的收盘位置；</li><li>价格是否重新被接受在旧区间内；</li><li>回踩低点是否破坏结构；</li><li>下一根 K 线能否沿原方向推进；</li><li>后续是否有机会形成③。</li></ol><p><img src="`+l+`" alt="有效回踩、影线假破与收盘失效的 K 线对比"></p><p><em>图 2：有效②看收盘与后续延续，不只看盘中影线。图中价格为构造示例。</em></p><h3 id="a-有效2-收盘守住" tabindex="-1">A. 有效②：收盘守住 <a class="header-anchor" href="#a-有效2-收盘守住" aria-label="Permalink to &quot;A. 有效②：收盘守住&quot;">​</a></h3><ul><li>回踩到 VWAP、突破线或需求区；</li><li>K 线收盘仍站在关键线上方；</li><li>回踩低点没有破坏结构；</li><li>后续突破回踩高点，形成③。</li></ul><p>这是标准的多头确认结构。</p><h3 id="b-影线假破-收回关键线" tabindex="-1">B. 影线假破：收回关键线 <a class="header-anchor" href="#b-影线假破-收回关键线" aria-label="Permalink to &quot;B. 影线假破：收回关键线&quot;">​</a></h3><p>价格盘中短暂跌破关键线，但收盘重新站回。此时不能因为影线就立即判定失效，也不能马上抢跑，应等待后续③。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>盘中跌破</span></span>
<span class="line"><span>→ 收盘收回关键线</span></span>
<span class="line"><span>→ 观察下一根是否继续承接</span></span>
<span class="line"><span>→ 等待③</span></span></code></pre></div><h3 id="c-真正失效-收盘跌破" tabindex="-1">C. 真正失效：收盘跌破 <a class="header-anchor" href="#c-真正失效-收盘跌破" aria-label="Permalink to &quot;C. 真正失效：收盘跌破&quot;">​</a></h3><ul><li>K 线实体收盘跌破关键线；</li><li>下一根无法重新站回；</li><li>反弹高点降低；</li><li>价格继续向需求区下方扩张。</li></ul><p>这时多头结构已经失效。不能因为“之前有需求区”就继续持有多单。</p><h2 id="三、3仍然是明确的执行信号" tabindex="-1">三、③仍然是明确的执行信号 <a class="header-anchor" href="#三、3仍然是明确的执行信号" aria-label="Permalink to &quot;三、③仍然是明确的执行信号&quot;">​</a></h2><p>本章的③仍然不是第三根 K 线，也不是某个指标名称，而是：</p><blockquote><p>回踩守住以后，价格突破回踩过程中形成的小高点。</p></blockquote><p>多头结构可以写成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 突破或收复关键位</span></span>
<span class="line"><span>② 回踩关键位并守住</span></span>
<span class="line"><span>③ 突破回踩结构高点</span></span></code></pre></div><p>空头结构完全对称：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 跌破关键位</span></span>
<span class="line"><span>② 反抽关键位但站不回去</span></span>
<span class="line"><span>③ 跌破反抽结构低点</span></span></code></pre></div><p>如果只是从需求区反弹，却没有突破回踩高点，就不能称为完整反转。</p><h2 id="四、这些-k-线一般是几分钟" tabindex="-1">四、这些 K 线一般是几分钟 <a class="header-anchor" href="#四、这些-k-线一般是几分钟" aria-label="Permalink to &quot;四、这些 K 线一般是几分钟&quot;">​</a></h2><p>示意图本身不固定周期，它表达的是结构关系，而不是某个特定时间长度。</p><p>对于 SPX 0DTE 日内交易，默认分工如下：</p><table tabindex="0"><thead><tr><th>周期</th><th>主要任务</th></tr></thead><tbody><tr><td>5 分钟</td><td>判断趋势、震荡、失败突破，标记主要供需区和关键位</td></tr><tr><td>1 分钟</td><td>执行①②③，寻找入场、失效点和时间退出</td></tr><tr><td>3 分钟</td><td>可选的过渡确认，用于过滤过于嘈杂的 1 分钟结构</td></tr><tr><td>15 分钟以上</td><td>观察更大的压力、支撑、前高和前低</td></tr></tbody></table><p>最实用的组合是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5分钟：价格突破关键位</span></span>
<span class="line"><span>→ 1分钟：回踩守住</span></span>
<span class="line"><span>→ 1分钟：出现③</span></span>
<span class="line"><span>→ 1分钟收盘确认后建仓</span></span></code></pre></div><p>例如 5 分钟突破 <code>7500</code>，1 分钟回踩到 <code>7500</code> 附近没有收盘跌破，随后 1 分钟突破回踩高点，这才是完整的多头候选。</p><p>如果 1 分钟出现③，但 5 分钟仍然明显处于供给区或下降结构中，信号应降级。可以等待 5 分钟收盘确认，或者直接放弃。</p><blockquote><p>5 分钟决定“能不能做”，1 分钟决定“在哪里做”。</p></blockquote><h2 id="五、建仓与止损" tabindex="-1">五、建仓与止损 <a class="header-anchor" href="#五、建仓与止损" aria-label="Permalink to &quot;五、建仓与止损&quot;">​</a></h2><p>学习阶段建议使用标准确认方式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>②回踩守住</span></span>
<span class="line"><span>→ 等待③突破</span></span>
<span class="line"><span>→ 等待③的1分钟K收盘</span></span>
<span class="line"><span>→ 检查目标空间</span></span>
<span class="line"><span>→ 再建立仓位</span></span></code></pre></div><h3 id="建仓方式" tabindex="-1">建仓方式 <a class="header-anchor" href="#建仓方式" aria-label="Permalink to &quot;建仓方式&quot;">​</a></h3><ul><li><strong>标准方式</strong>：③突破并收盘确认后建仓；</li><li><strong>保守方式</strong>：③后等待一次小幅二次回踩，再建立主要仓位；</li><li><strong>激进方式</strong>：②守住时提前试仓，但只能使用更小风险，暂不作为默认方法。</li></ul><p>没有一种订单方式可以同时做到最低价格、完全确认和永不错过。限价单可能在影线刺穿时成交，随后价格立即跌回；等待收盘则可能成交更高或错过。因此学习阶段优先保护结构证据，而不是追求最低成本。</p><h3 id="止损方式" tabindex="-1">止损方式 <a class="header-anchor" href="#止损方式" aria-label="Permalink to &quot;止损方式&quot;">​</a></h3><p>多头止损通常放在：</p><ul><li>②回踩形成的最低点下方；</li><li>或需求区下方；</li><li>或价格重新被接受在旧区间内的位置。</li></ul><p>如果只是盘中影线跌破，但收盘收回，不应只因为影线本身就立刻止损。若实体收盘跌破，并且后续无法重新收回，则结构失效。</p><h2 id="六、结合之前的六股票截图" tabindex="-1">六、结合之前的六股票截图 <a class="header-anchor" href="#六、结合之前的六股票截图" aria-label="Permalink to &quot;六、结合之前的六股票截图&quot;">​</a></h2><p><img src="`+i+`" alt="六只股票盘中结构复盘"></p><p><em>图 3：六只大型科技股的历史盘中截图，用于练习“位置—环境—结构—确认”的观察顺序，不是实时交易点位。</em></p><h3 id="aapl" tabindex="-1">AAPL <a class="header-anchor" href="#aapl" aria-label="Permalink to &quot;AAPL&quot;">​</a></h3><p>AAPL 从约 <code>322</code> 附近需求区反弹，但上方约 <code>324.3—324.6</code> 附近仍有压力。正确的问题不是“它已经涨了，能不能追”，而是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>是否收复上方关键压力？</span></span>
<span class="line"><span>回踩是否守住？</span></span>
<span class="line"><span>是否形成③？</span></span></code></pre></div><h3 id="googl" tabindex="-1">GOOGL <a class="header-anchor" href="#googl" aria-label="Permalink to &quot;GOOGL&quot;">​</a></h3><p>GOOGL 从约 <code>346.8—347</code> 附近需求区反弹，但仍需观察能否收复约 <code>349.58</code> 附近 VWAP。没有收复 VWAP 和形成③之前，属于反弹观察，不是明确多头。</p><h3 id="tsla" tabindex="-1">TSLA <a class="header-anchor" href="#tsla" aria-label="Permalink to &quot;TSLA&quot;">​</a></h3><p>TSLA 从低位需求区反弹较强，但靠近上方供给区时，强势本身不能成为追多理由。应等待突破前高后的回踩，或等待价格回到 VWAP/需求区后重新出现③。</p><h3 id="nvda、meta、msft" tabindex="-1">NVDA、META、MSFT <a class="header-anchor" href="#nvda、meta、msft" aria-label="Permalink to &quot;NVDA、META、MSFT&quot;">​</a></h3><ul><li>NVDA：冲高回落后，先看需求区是否守住，再看能否重新收复关键线；</li><li>META：若价格在平衡区和 VWAP 附近反复穿越，属于方向不清，等待边界；</li><li>MSFT：即使相对稳定，也需要确认价格不在区间中间追单。</li></ul><h2 id="七、本章执行卡" tabindex="-1">七、本章执行卡 <a class="header-anchor" href="#七、本章执行卡" aria-label="Permalink to &quot;七、本章执行卡&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前周期：5分钟环境 / 1分钟执行</span></span>
<span class="line"><span>价格位置：Demand / Equilibrium / Premium</span></span>
<span class="line"><span>关键线：VWAP、ORB、前高低或节点</span></span>
<span class="line"><span>是否完成①：</span></span>
<span class="line"><span>②回踩最低点：</span></span>
<span class="line"><span>②收盘是否守住：是 / 否</span></span>
<span class="line"><span>是否出现③：</span></span>
<span class="line"><span>结构失效：</span></span>
<span class="line"><span>第一目标：</span></span>
<span class="line"><span>目标空间是否足够：</span></span></code></pre></div><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>需求区只提供观察位置</span></span>
<span class="line"><span>VWAP提供环境过滤</span></span>
<span class="line"><span>②证明回踩是否有效</span></span>
<span class="line"><span>③提供明确执行信号</span></span>
<span class="line"><span>后续延续验证交易是否得到市场接受</span></span></code></pre></div><p>最重要的一句话：</p><blockquote><p>影线可以容忍，收盘结构不能忽略；从需求区反弹，不等于已经反转。</p></blockquote><blockquote><p>本章用于交易教育和个人研究，不构成投资建议。图例为构造示例，不能直接视为实时买卖信号。</p></blockquote>`,74)])])}const k=s(o,[["render",c]]);export{m as __pageData,k as default};
